INSERT INTO `timesheets` (`timesheet_id`, `tutor_id`, `student_id`, `user_id`, `date`, `time`, `duration`, `duration2`, `description`, `hourly_pay_rate`, `created_at`, `updated_at`) VALUES
(31, 38, 43, 40, '2020-11-18', NULL, '1:00', '1', 'It was a pleasure to begin work with Mallory today to assist her in her algebra class.  Mallory is a bright young lady with stellar character traits who is struggling a bit with algebraic concepts and applications. After some technical difficulties with Zoom, we moved over to Google Meet (hopefully only this one time) and reviewed the concept of functions. I suggested that in the beginning phases of the tutoring engagement, it may be advisable to meet more than once per week to help Mallory to more quickly level the playing field before settling into a once per week rhythm later. Mallory will discuss this idea with her mother before we are in contact to set up a schedule. I look forward to working with Mallory!', '50', '2020-11-18 16:43:24', '2020-11-18 16:43:24'),
(32, 42, 44, 43, '2020-11-18', NULL, '1:00', '1', 'Sam and I continued working through the book \"Mythology\" and worked on some flashcards that focused on identifying correct word usage. He\'s growing in confidence and is reading out loud with increased fluency.', '45', '2020-11-19 00:23:47', '2020-11-19 00:23:47'),
(33, 45, 45, 46, '2020-11-19', NULL, '1:00', '1', 'First half of the session consisted of reading comprehension, close-reading and discussion of recent article about popularity of Among Us. After, we reviewed examples of figurative language and student demonstrated significant improvement since previous attempts.', '50', '2020-11-20 19:45:24', '2020-11-20 19:45:24'),
(35, 34, 45, 46, '2020-11-21', NULL, '1:00', '1', 'Learned to play minesweeper to develop logical reasoning and critical thinking skills.', '75', '2020-11-21 21:06:46', '2020-11-21 21:06:46'),
(36, 34, 47, 48, '2020-11-24', NULL, '1:00', '1', 'Solving rational equations, finding vertical and horizontal asymptotes, holes in the graph, factoring trinomials and binomials.', '63', '2020-11-24 20:08:27', '2020-11-24 20:08:27'),
(37, 34, 46, 47, '2020-11-24', NULL, '1:00', '1', 'Review radical expressions homework. Reviewed perfect square trinomials, factoring rational expressions. Assigned simplifying radicals homework.', '70', '2020-11-24 20:09:28', '2020-11-24 20:09:28'),
(38, 38, 43, 40, '2020-11-25', NULL, '1:00', '1', 'Mallory and I had a great session, as we reviewed the \"only 2\" problems she answered incorrectly on a recent exam, and then proceeded to review linear functions. No technical problems this time...Yay!!  I advised Mallory to write down the information given and tools necessary to come up with a solution, and most of all, keep cool and \"take your time\".  I am truly enjoying working with Mallory,. and look forward to accompany her towards  super growth and understanding!  Remember Mallory...feathers on the outside!!', '50', '2020-11-25 23:03:23', '2020-11-25 23:03:23'),
(39, 44, 45, 46, '2020-11-30', NULL, '1:00', '1', 'Meet and greet. We worked on Brendon assignment. We also touched base on what he needed the most work on.', '40', '2020-11-30 23:24:57', '2020-11-30 23:24:57'),
(40, 42, 48, 49, '2020-12-01', NULL, '1:00', '1', 'I worked with Leena in her Math class where she is showing huge improvement both with her confidence and math skills. Her class ended early and we did some practice on her prodigy program.', '45', '2020-12-02 19:37:11', '2020-12-02 19:37:11'),
(41, 42, 44, 43, '2020-12-02', NULL, '1:00', '1', 'Sam and I continued reading through our Mythology book where he is showing increased fluency and increased ability to sound out difficult words. We also did some practice with sight words to shore up his basic reading skills.', '45', '2020-12-02 19:38:34', '2020-12-02 19:38:34'),
(44, 34, 47, 48, '2020-12-01', NULL, '1:00', '1', 'Graphing square root and cube root functions and their transformations.', '63', '2020-12-02 19:44:18', '2020-12-02 19:44:18'),
(45, 34, 46, 47, '2020-12-01', NULL, '1:00', '1', 'Review of functions and nested functions practice.', '70', '2020-12-02 19:44:45', '2020-12-02 19:44:45'),
(46, 41, 53, 54, '2020-12-02', NULL, '1:00', '1', 'Sampling distributions of sample proportions, conditions for normality, finding probabilities using sampling distribution', '50', '2020-12-02 23:13:53', '2020-12-02 23:13:53'),
(47, 34, 45, 46, '2020-12-02', NULL, '1:00', '1', 'Minesweeper, word problems with adding decimals, and time word problem. Word problems from Math Counts.', '75', '2020-12-03 01:23:26', '2020-12-03 01:23:26'),
(48, 42, 46, 47, '2020-12-02', NULL, '0:30', '0.5', 'Zoe and I met on Zoom and discussed her interests and goals for the school year. We\'re planning to supplement her school work with more challenging reading, journals, and lessons on text analysis.', '45', '2020-12-03 01:42:09', '2020-12-03 01:42:09'),
(49, 38, 43, 40, '2020-12-02', NULL, '1:00', '1', 'Mallory was \"on her game\" today as we reviewed exponent properties and exponential decay.  One area that \"got in our way\" a bit was negative exponents, but after a few practice practice problems, we gently \"pushed them aside\" to move on to more of a challenge.  Mallory then proceeded to demonstrate her expertise in setting up exponential decay equations....while at the same time wearing her new \"daily wear\" contact lenses.  Mallory was certainly seeing things \"very clearly\"! Great work Mallory!', '50', '2020-12-03 02:42:53', '2020-12-03 02:42:53'),
(50, 45, 45, 46, '2020-12-03', NULL, '1:00', '1', 'Reviewed parts of speech - noun, adjective, verb, adverb, preposition, interjection, pronoun. Labeled sample sentences. Brendon scored 12/20 on the pre-test and 18/20 on the post-test. Next session: take notes on terms and examples and re-test. Differentiate types of verbs.', '50', '2020-12-03 23:36:19', '2020-12-03 23:36:19'),
(51, 42, 48, 49, '2020-12-03', NULL, '1:00', '1', 'I sat in on Leena\'s math class again, helping her stay focused and answering her questions. She continues to grow in confidence and is actually enjoying math classes. We are going to go back to meeting on Wednesdays so I can continue to reinforce what she\'s learning in class, but I will continue to see her on Tuesdays to keep abreast of what she\'s doing in school.', '45', '2020-12-04 15:00:25', '2020-12-04 15:00:25'),
(52, 34, 39, 35, '2020-12-04', NULL, '1:00', '1', 'Multiplication practice: 4, 6, 7, 8. Online games practice SPUQ and Multiplication Cat.', '70', '2020-12-05 04:14:21', '2020-12-05 04:14:21'),
