(74, 'Melanie', NULL, 'tutor', 'melaniedong01@gmail.com', '$2y$10$EUO42quLfXYI.cXWYi9gjOo9th2RhWLoHbONUvGwnPfU1N.C9kwMW', NULL, NULL, NULL, NULL, 'Eastern Time', 'inactive', '410-718-8884', 'profile-1621388179-940974.jpg', 'Hi! I\'m Melanie Dong and I am a student at the University of Pittsburgh School of Nursing, where I have the goal of becoming a Nurse Anesthetist. I love working with kids and have had the pleasure of tutoring elementary school students both one-on-one and in a group setting.  I love to tutor grammar, reading, writing, and math! I live in Ellicott City and can either tutor in-person or over Zoom. I look forward to working with you!', 'Subscribe', 'sOCQDekCT0IUdqrSp6AWJqS0sqUnBavCb27ivdqVrwhs1XgmDLkvdVgBwJBt', NULL, NULL, NULL, NULL, '2021-05-17 23:53:31', '2025-02-04 01:29:36'),
